420	        });
421	        
422	        const data = await response.json();
423	        
424	        if (!data.success) {
425	            console.error('保存状态失败:', data.message);
426	            // 恢复原状态
427	            location.reload();
428	        }
429	    } catch (error) {
430	        console.error('保存状态时发生错误:', error);
431	    }
432	}

